#include <stdio.h>
#include <string.h>

int main(void) {
    char buf1[64], buf2[64], buf3[64];
    int code = 404;
    char *status = "Not Found";
    double temp = 36.6;
    sprintf(buf1, "Error %d: %s", code, status);
    sprintf(buf2, "Temp: %.1f C", temp);
    sprintf(buf3, "%s | %s", buf1, buf2);
    printf("%s\n", buf1);
    printf("%s\n", buf2);
    printf("%s\n", buf3);
    printf("len1=%d len2=%d len3=%d\n", (int)strlen(buf1), (int)strlen(buf2), (int)strlen(buf3));
    return 0;
}

